import React, { useState } from "react";
import { useCart } from "../context/CartContext";

const CheckoutPage = () => {
  const { cartItems, updateQuantity, removeFromCart } = useCart();
  const [formData, setFormData] = useState({
    name: "",
    address: "",
    payment: "",
  });

  const total = cartItems.reduce(
    (sum, item) => sum + item.price * item.quantity,
    0
  );

  const handleSubmit = (e) => {
    e.preventDefault();
    alert("✅ Order placed successfully!");
  };

  return (
    <div
      style={{
        maxWidth: "900px",
        margin: "30px auto",
        display: "grid",
        gridTemplateColumns: "1fr 1fr",
        gap: "30px",
        padding: "20px",
        background: "#fff",
        borderRadius: "10px",
        boxShadow: "0 0 15px rgba(0,0,0,0.1)",
      }}
    >
      {/* 🛒 Cart Section */}
      <div>
        <h2>Your Cart</h2>
        {cartItems.length === 0 ? (
          <p>Cart is empty</p>
        ) : (
          cartItems.map((item) => (
            <div
              key={item.id}
              style={{
                borderBottom: "1px solid #eee",
                padding: "10px 0",
                display: "flex",
                alignItems: "center",
                gap: "10px",
              }}
            >
              <img
                src={item.image}
                alt={item.name}
                style={{ width: "70px", height: "70px", borderRadius: "6px" }}
              />
              <div style={{ flex: 1 }}>
                <h4 style={{ margin: 0 }}>{item.name}</h4>
                <p style={{ margin: "5px 0" }}>₹{item.price}</p>
                <div style={{ display: "flex", alignItems: "center" }}>
                  <button
                    onClick={() => updateQuantity(item.id, item.quantity - 1)}
                    style={{ padding: "3px 8px" }}
                  >
                    -
                  </button>
                  <span style={{ margin: "0 8px" }}>{item.quantity}</span>
                  <button
                    onClick={() => updateQuantity(item.id, item.quantity + 1)}
                    style={{ padding: "3px 8px" }}
                  >
                    +
                  </button>
                </div>
                <button
                  onClick={() => removeFromCart(item.id)}
                  style={{
                    background: "none",
                    border: "none",
                    color: "red",
                    cursor: "pointer",
                    marginTop: "5px",
                  }}
                >
                  Remove
                </button>
              </div>
            </div>
          ))
        )}
        {cartItems.length > 0 && (
          <h3 style={{ marginTop: "15px" }}>Total: ₹{total.toFixed(2)}</h3>
        )}
      </div>

      {/* 🏠 Checkout Form */}
      <div>
        <h2>Checkout</h2>
        <form onSubmit={handleSubmit}>
          <input
            type="text"
            placeholder="Full Name"
            required
            value={formData.name}
            onChange={(e) =>
              setFormData({ ...formData, name: e.target.value })
            }
            style={{
              width: "100%",
              marginBottom: "10px",
              padding: "8px",
              border: "1px solid #ccc",
              borderRadius: "5px",
            }}
          />
          <textarea
            placeholder="Address"
            required
            value={formData.address}
            onChange={(e) =>
              setFormData({ ...formData, address: e.target.value })
            }
            style={{
              width: "100%",
              height: "100px",
              marginBottom: "10px",
              padding: "8px",
              border: "1px solid #ccc",
              borderRadius: "5px",
            }}
          />
          <input
            type="text"
            placeholder="Payment Method (e.g. UPI / COD)"
            required
            value={formData.payment}
            onChange={(e) =>
              setFormData({ ...formData, payment: e.target.value })
            }
            style={{
              width: "100%",
              marginBottom: "10px",
              padding: "8px",
              border: "1px solid #ccc",
              borderRadius: "5px",
            }}
          />
          <button
            type="submit"
            style={{
              width: "100%",
              background: "#28a745",
              color: "#fff",
              padding: "10px",
              border: "none",
              borderRadius: "5px",
              cursor: "pointer",
            }}
          >
            Place Order
          </button>
        </form>
      </div>
    </div>
  );
};

export default CheckoutPage;
